import { listTenants, resolve, API_VERSION, GHL_BASE } from '../../lib/ghl-tenant-resolver.mjs';

const tenants = listTenants();
if (!tenants.length) {
  const d = resolve();
  if (d.token && d.locationId) tenants.push({ alias: d.alias, locationId: d.locationId });
}

async function run() {
  const out = [];
  for (const t of tenants) {
    const { token, locationId, alias } = resolve(t.alias || t.locationId);
    const headers = {
      Authorization: `Bearer ${token}`,
      Version: API_VERSION,
      'Content-Type': 'application/json',
    };

    const get = async (ep) => {
      const r = await fetch(`${GHL_BASE}${ep}`, { headers });
      if (!r.ok) return { __error: await r.text(), status: r.status, ep };
      return r.json();
    };

    const campaigns = await get(`/campaigns/?locationId=${encodeURIComponent(locationId)}`);
    const allCampaigns = campaigns.campaigns || [];
    const sent = allCampaigns.reduce((s, c) => s + (c.sent || 0), 0);
    const delivered = allCampaigns.reduce((s, c) => s + (c.delivered || 0), 0);
    const opened = allCampaigns.reduce((s, c) => s + (c.opened || 0), 0);
    const clicked = allCampaigns.reduce((s, c) => s + (c.clicked || 0), 0);

    const oppsRes = await get(`/opportunities/search?location_id=${encodeURIComponent(locationId)}&limit=100`);
    const opps = oppsRes.opportunities || oppsRes.data || [];
    const pipelineValue = opps.reduce((s, o) => s + (Number(o.monetaryValue) || 0), 0);
    const won = opps.filter((o) => String(o.status || '').toLowerCase() === 'won').length;

    out.push({
      alias,
      locationId,
      campaignCount: allCampaigns.length,
      sent,
      delivered,
      opened,
      clicked,
      openRate: delivered ? (opened / delivered) * 100 : null,
      conversionRate: delivered ? (clicked / delivered) * 100 : null,
      opportunityCount: opps.length,
      wonCount: won,
      winRate: opps.length ? (won / opps.length) * 100 : null,
      pipelineValue,
      errors: [campaigns.__error ? campaigns : null, oppsRes.__error ? oppsRes : null].filter(Boolean),
    });
  }

  console.log(JSON.stringify({ generatedAt: new Date().toISOString(), tenantCount: out.length, tenants: out }, null, 2));
}

run().catch((e) => {
  console.error(e);
  process.exit(1);
});

import { listTenants, resolve, API_VERSION, GHL_BASE } from '../../lib/ghl-tenant-resolver.mjs';

const tenants = listTenants();
if (!tenants.length) {
  const d = resolve();
  if (d.token && d.locationId) tenants.push({ alias: d.alias, locationId: d.locationId });
}

const get = async (token, ep) => {
  const r = await fetch(`${GHL_BASE}${ep}`, {
    headers: { Authorization: `Bearer ${token}`, Version: API_VERSION, 'Content-Type': 'application/json' },
  });
  if (!r.ok) return { __error: await r.text(), status: r.status, ep };
  return r.json();
};

const out = [];
for (const t of tenants) {
  const { token, locationId, alias } = resolve(t.alias || t.locationId);
  const pipelinesRes = await get(token, `/opportunities/pipelines?locationId=${encodeURIComponent(locationId)}`);
  const pipelines = pipelinesRes.pipelines || [];
  const detail = [];
  for (const p of pipelines) {
    const oppsRes = await get(token, `/opportunities/?locationId=${encodeURIComponent(locationId)}&pipelineId=${encodeURIComponent(p.id)}&limit=100`);
    const opps = oppsRes.opportunities || oppsRes.data || [];
    detail.push({
      pipelineId: p.id,
      pipelineName: p.name,
      opportunities: opps.length,
      value: opps.reduce((s, o) => s + (Number(o.monetaryValue) || 0), 0),
    });
  }
  out.push({ alias, locationId, pipelineCount: pipelines.length, pipelines: detail, error: pipelinesRes.__error ? pipelinesRes : null });
}

console.log(JSON.stringify(out, null, 2));

